#include <stdio.h>
#include <string.h>
int main() {
    char s[100001];
    int q, l, r;
    scanf("%s %d", s, &q);
    while (q--) {
        scanf("%d %d", &l, &r);
        int count = 0;
        int freq[26] = {0};
        for (int i = l - 1; i < r; i++) {
            if (!freq[s[i] - 'a']) {
                count++;
                freq[s[i] - 'a'] = 1;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

