import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String s = scanner.next();
        int q = scanner.nextInt();
        while (q-- > 0) {
            int l = scanner.nextInt();
            int r = scanner.nextInt();
            int count = 0;
            boolean[] freq = new boolean[26];
            for (int i = l - 1; i < r; i++) {
                if (!freq[s.charAt(i) - 'a']) {
                    count++;
                    freq[s.charAt(i) - 'a'] = true;
                }
            }
            System.out.println(count);
        }
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let s, q;
readline.on('line', line => {
    if (i === 0) {
        s = line;
    } else if (i === 1) {
        q = parseInt(line);
    } else {
        let [l, r] = line.split(' ').map(x => parseInt(x));
        let count = 0;
        let freq = new Array(26).fill(false);
        for (let j = l - 1; j < r; j++) {
            if (!freq[s.charCodeAt(j) - 'a'.charCodeAt(0)]) {
                count++;
                freq[s.charCodeAt(j) - 'a'.charCodeAt(0)] = true;
            }
        }
        console.log(count);
        if (i === q + 1) {
            readline.close();
        }
    }
    i++;
});
